+fn count_rows(conn: &Connection, table: &str) -> Result<u64, String> {
+    let sql = format!("SELECT count(*) FROM {}", quote_ident(table));
+    conn.query_row(&sql, [], |r| r.get::<_, u64>(0))
+        .map_err(|e| format!("count_rows({table}): {e}"))
+}
