+fn sqlite_magic_header_ok(path: &Path) -> io::Result<bool> {
+    use std::io::Read as _;
+    const MAGIC: &[u8; 16] = b"SQLite format 3\0";
+    let mut f = std::fs::File::open(path)?;
+    let mut buf = [0u8; 16];
+    if f.read_exact(&mut buf).is_err() {
+        return Ok(false);
+    }
+    Ok(&buf == MAGIC)
+}
